oracle_python:
class Solution:
    def rand10(self):
        while True:
            row = rand7()
            col = rand7()
            idx = (row - 1) * 7 + col
            if idx <= 40:
                return (idx - 1) % 10 + 1

solutions.python:
class Solution:
    def rand10(self):
        while True:
            v = (rand7() - 1) * 7 + rand7()
            if v <= 40:
                return (v - 1) % 10 + 1

